mapper.update:
update departments_51
set parent_dept_id = #{parentDeptId},
    dept_name      = #{deptName},
    version        = #{version} + 1,
    updated_at     = #{updatedAt},
    updated_by     = #{updatedBy}
where dept_id      = #{deptId}
  and version      = #{version}
  and is_deleted   = 'n'

update departments_51
set is_deleted = 'y',
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where dept_id  = #{deptId}
  and is_deleted = 'n'
